+fn testFunc() void {
+    var x: u64 = 0;
+    for (0..100) |i| {
+        x += i;
+    }
+    std.mem.doNotOptimizeAway(&x);
+}
+
+test "timeit basic" {
+    const t = timeit(&testFunc, 100);
+    try std.testing.expect(t > 0);
+    try std.testing.expect(t < 1.0); // Should complete in under 1 second
+}
