+        .allocator = allocator,
+        .stmt = &testFunc,
+    };
+    const times = try timer.repeat(3, 100);
+    defer allocator.free(times);
+    try std.testing.expectEqual(@as(usize, 3), times.len);
+    for (times) |t| {
+        try std.testing.expect(t > 0);
+    }
